      {"question_id":"dw_beg_001","type":"mcq","question":"What is the difference between a fact table and a dimension table in a data warehouse?","options":["Fact tables store metadata; dimensions store transactions","Fact tables store measurable events/metrics; dimensions provide context","No difference","Fact tables are smaller than dimensions"],"correct_answer":1,"explanation":"Fact tables store quantitative metrics like sales amount or page views. Dimension tables provide descriptive context like product name or customer region. Facts reference dimensions via foreign keys.","difficulty_score":2,"time_seconds":30,"tags":["star_schema","fact_tables","dimension_tables"],"prerequisites":[],"common_mistakes":["Placing descriptive attributes in fact tables"],"learning_resources":["https://www.kimballgroup.com/"],"real_world_context":"Star schema design is the foundation of all dimensional data warehouse modelling."},
      {"question_id":"dw_beg_002","type":"mcq","question":"What does OLAP stand for?","options":["Online Analytical Processing","Online Application Protocol","Offline Logical Analysis Pipeline","Open Layered Architecture Platform"],"correct_answer":0,"explanation":"OLAP (Online Analytical Processing) supports complex analytical queries on large datasets, typically aggregating historical data. OLTP (Online Transaction Processing) handles high-volume insert/update transactional operations.","difficulty_score":1,"time_seconds":30,"tags":["OLAP","OLTP","fundamentals"],"prerequisites":[],"common_mistakes":["Confusing OLAP with OLTP workloads"],"learning_resources":["https://docs.microsoft.com/en-us/azure/architecture/data-guide/relational-data/online-analytical-processing"],"real_world_context":"BI tools like Tableau query OLAP systems (Snowflake, BigQuery, Redshift) for dashboards."},
      {"question_id":"dw_beg_003","type":"true_false","question":"A snowflake schema normalises dimension tables, whereas a star schema keeps them denormalised.","correct_answer":True,"explanation":"Star schema uses denormalised dimension tables (all attributes in one table). Snowflake schema normalises dimensions into multiple related tables, reducing redundancy but adding join complexity.","difficulty_score":3,"time_seconds":30,"tags":["star_schema","snowflake_schema","normalisation"],"prerequisites":["dw_beg_001"],"common_mistakes":["Confusing the two schemas"],"learning_resources":["https://www.kimballgroup.com/"],"real_world_context":"Star schema is preferred in most modern cloud data warehouses for query performance."},
