      {"question_id":"dw_adv_002","type":"mcq","question":"What is the Kimball Bus Matrix used for?","options":["Monitoring data pipeline health","Documenting which business processes share conformed dimensions","Scheduling ETL jobs","Encrypting warehouse data"],"correct_answer":1,"explanation":"The Kimball Bus Matrix maps business processes (rows) to conformed dimensions (columns). It ensures different fact tables use the same dimension definitions, enabling cross-process analysis in a data warehouse.","difficulty_score":8,"time_seconds":120,"tags":["Kimball","bus_matrix","conformed_dimensions","dimensional_modelling"],"prerequisites":["dw_adv_001"],"common_mistakes":["Building siloed fact tables without conformed dimensions"],"learning_resources":["https://www.kimballgroup.com/data-warehouse-business-intelligence-resources/kimball-techniques/"],"real_world_context":"The Bus Matrix is the design artefact for enterprise data warehouse governance."}
